import{_ as x}from"./_plugin-vue_export-helper-DlAUqK2U.js";import{f as y,g,c as l,a as e,F as i,r as v,d as p,h as u,o as n,n as f,t as b,i as h}from"./index-CqX1W9Wc.js";const w={class:"flex min-h-[100dvh] bg-gray-50"},k={class:"hidden lg:flex flex-col w-64 shrink-0 border-r border-gray-200 bg-white sticky top-0 h-[100dvh] overflow-y-auto py-10 px-6"},E={class:"flex flex-col space-y-1"},T=["onClick"],q=["onClick"],$={class:"w-full lg:w-2/3 mx-auto px-6 py-16 lg:py-12"},L={id:"overview",class:"mb-14"},C={class:"grid grid-cols-1 sm:grid-cols-3 gap-4 mt-8"},z={__name:"Documentation",setup(S){const r=u("overview"),m=[{id:"overview",title:"Resumen"},{id:"quick-start",title:"Inicio Rápido"},{id:"element-types",title:"Tipos de Elementos"},{id:"environments",title:"Entornos"},{id:"math",title:"Matemáticas"},{id:"commands",title:"Comandos de Texto"},{id:"cross-references",title:"Referencias Cruzadas"},{id:"complete-example",title:"Ejemplo Completo"},{id:"parser-output",title:"Salida del Analizador"},{id:"limitations",title:"Limitaciones"}];function s(c){const a=document.getElementById(c);a&&a.scrollIntoView({behavior:"smooth",block:"start"})}let d=null;return y(()=>{const c=document.querySelectorAll("section[id]");d=new IntersectionObserver(a=>{for(const t of a)t.isIntersecting&&(r.value=t.target.id)},{rootMargin:"-20% 0px -70% 0px"}),c.forEach(a=>d.observe(a))}),g(()=>d==null?void 0:d.disconnect()),(c,a)=>(n(),l("div",w,[e("aside",k,[a[3]||(a[3]=e("p",{class:"text-xs font-bold uppercase tracking-widest text-gray-400 mb-4"},"Documentación",-1)),e("nav",E,[(n(),l(i,null,v(m,t=>(n(),l(i,{key:t.id},[e("button",{onClick:o=>s(t.id),class:f(["text-left px-3 py-2 rounded-lg text-sm transition-colors",r.value===t.id?"bg-blue-50 text-blue-700 font-semibold":"text-gray-600 hover:bg-gray-100 hover:text-gray-900"])},b(t.title),11,T),t.children?(n(!0),l(i,{key:0},v(t.children,o=>(n(),l("button",{key:o.id,onClick:X=>s(o.id),class:f(["text-left pl-6 pr-3 py-1.5 rounded-lg text-sm transition-colors",r.value===o.id?"bg-blue-50 text-blue-700 font-semibold":"text-gray-500 hover:bg-gray-100 hover:text-gray-800"])},b(o.title),11,q))),128)):h("",!0)],64))),64))])]),e("main",$,[e("section",L,[a[7]||(a[7]=e("p",{class:"text-4xl font-bold font-plex mb-4"},"Documentación de EduWords",-1)),a[8]||(a[8]=e("p",{class:"text-lg text-gray-600"}," Guía completa para escribir libros matemáticos interactivos con LaTeX. ",-1)),e("div",C,[e("button",{onClick:a[0]||(a[0]=t=>s("quick-start")),class:"flex flex-col justify-between p-5 rounded-xl bg-gradient-to-br from-green-400 to-blue-500 text-white text-left transition-opacity hover:opacity-90 active:opacity-80"},[...a[4]||(a[4]=[e("span",{class:"flex items-center text-xl mb-3"},[e("i",{class:"icon icon-book"}),e("p",{class:"font-bold font-plex ml-3 text-base"},"Inicio Rápido")],-1),e("p",{class:"font-nunito text-sm opacity-90 mb-3"},"Aprende lo básico y escribe tu primer documento.",-1)])]),e("button",{onClick:a[1]||(a[1]=t=>s("environments")),class:"flex flex-col justify-between p-5 rounded-xl bg-gradient-to-br from-purple-400 to-pink-500 text-white text-left transition-opacity hover:opacity-90 active:opacity-80"},[...a[5]||(a[5]=[e("span",{class:"flex items-center text-xl mb-3"},[e("i",{class:"icon icon-file"}),e("p",{class:"font-bold font-plex ml-3 text-base"},"Entornos")],-1),e("p",{class:"font-nunito text-sm opacity-90"},"Teoremas, demostraciones, definiciones y más.",-1)])]),e("button",{onClick:a[2]||(a[2]=t=>s("math")),class:"flex flex-col justify-between p-5 rounded-xl bg-gradient-to-br from-orange-400 to-red-500 text-white text-left transition-opacity hover:opacity-90 active:opacity-80"},[...a[6]||(a[6]=[e("span",{class:"flex items-center text-xl mb-3"},[e("i",{class:"icon icon-code"}),e("p",{class:"font-bold font-plex ml-3 text-base"},"Matemáticas")],-1),e("p",{class:"font-nunito text-sm opacity-90"},"Matemáticas en línea y en bloque con KaTeX.",-1)])])]),a[9]||(a[9]=p('<a href="https://m.youtube.com/playlist?list=PL2FIypMaf6V0d3PN8pjNZ9TTyL3i5FUtw" target="_blank" rel="noopener noreferrer" class="flex items-center gap-4 mt-6 p-4 rounded-xl bg-white border border-gray-200 hover:border-red-300 hover:bg-red-50 transition-colors group" data-v-1e75afea><i class="icon icon-youtube text-2xl text-red-500" data-v-1e75afea></i><div class="flex-1 min-w-0" data-v-1e75afea><p class="font-semibold text-gray-800 group-hover:text-red-700 text-sm" data-v-1e75afea>Curso de LaTeX en YouTube</p><p class="text-xs text-gray-500 mt-0.5" data-v-1e75afea>¿Nuevo en LaTeX? Este curso es un excelente punto de partida para aprender la sintaxis básica.</p></div><i class="icon icon-arrow_right text-gray-400 group-hover:text-red-400 shrink-0" data-v-1e75afea></i></a><div class="mt-10 flex flex-col gap-4 text-gray-700 leading-relaxed" data-v-1e75afea><p data-v-1e75afea><code class="code-inline" data-v-1e75afea>larex</code> es un analizador de LaTeX que convierte tus documentos en libros web interactivos. Si ya conoces LaTeX, puedes escribir contenido de inmediato, sin aprender nueva sintaxis. El analizador soporta un subconjunto cuidadosamente seleccionado de comandos LaTeX optimizado para contenido matemático y educativo. </p><p data-v-1e75afea> Los documentos se renderizan con KaTeX para las matemáticas e incluyen funciones interactivas como notas clicables, referencias cruzadas y entornos de teoremas estructurados. </p></div>',2))]),a[10]||(a[10]=p(`<hr class="border-gray-200 mb-14" data-v-1e75afea><section id="quick-start" class="mb-14" data-v-1e75afea><h2 class="text-2xl font-bold font-plex mb-2" data-v-1e75afea>Inicio Rápido</h2><p class="text-sm text-gray-400 mb-6" data-v-1e75afea>Escribe tu primer libro interactivo</p><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Documento Mínimo</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Un documento válido requiere al menos la declaración <code class="code-inline" data-v-1e75afea>\\documentclass</code> y el envoltorio <code class="code-inline" data-v-1e75afea>\\begin{document}</code> / <code class="code-inline" data-v-1e75afea>\\end{document}</code>: </p><div class="code-block mb-8" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\documentclass</span><span class="text-gray-300" data-v-1e75afea>{article}</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{document}</span></div><div class="mt-2" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\section</span><span class="text-gray-300" data-v-1e75afea>{Introduction}</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>Welcome to my interactive book!</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{document}</span></div></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Estructura del Proyecto</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Para proyectos más grandes, divide tu contenido en varios archivos: </p><pre class="code-block mb-6" data-v-1e75afea>book/                    # Project root
  main.tex               # Entry point
  chapters/
    intro.tex
    chapter1.tex
  assets/
    images/
      diagram.png</pre><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Inclusión de Archivos</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Usa <code class="code-inline" data-v-1e75afea>\\include{path}</code> para incluir archivos externos. La ruta es relativa al archivo <code class="code-inline" data-v-1e75afea>.tex</code> principal y la extensión <code class="code-inline" data-v-1e75afea>.tex</code> es opcional: </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\include</span><span class="text-gray-300" data-v-1e75afea>{chapters/intro}</span></div><div class="mt-2" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\include</span><span class="text-gray-300" data-v-1e75afea>{chapters/chapter1}</span></div></div><p class="text-gray-600 text-sm mb-8" data-v-1e75afea> Los archivos incluidos se resuelven recursivamente antes del análisis. Puedes anidar includes en múltiples niveles. </p><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Usando el Compilador</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Ejecuta el analizador desde el directorio del compilador: </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-green-400" data-v-1e75afea>python</span><span class="text-gray-300" data-v-1e75afea> -m larex </span><span class="text-yellow-300" data-v-1e75afea>path/to/document.tex</span></div></div><p class="text-gray-600 text-sm mb-4 leading-relaxed" data-v-1e75afea> Muestra el AST JSON en stdout, o usa la bandera <code class="code-inline" data-v-1e75afea>-f</code> para guardar la salida en <code class="code-inline" data-v-1e75afea>examples/dist/</code>: </p><div class="code-block mb-4" data-v-1e75afea><span class="text-green-400" data-v-1e75afea>python</span><span class="text-gray-300" data-v-1e75afea> -m larex </span><span class="text-yellow-300" data-v-1e75afea>document.tex</span><span class="text-gray-300" data-v-1e75afea> -f</span></div></section><hr class="border-gray-200 mb-14" data-v-1e75afea><section id="element-types" class="mb-14" data-v-1e75afea><h2 class="text-2xl font-bold font-plex mb-2" data-v-1e75afea>Cómo se Leen los Elementos</h2><p class="text-sm text-gray-400 mb-6" data-v-1e75afea>Entendiendo los modos raw, kv y parsed</p><p class="text-gray-700 mb-6 leading-relaxed" data-v-1e75afea> El analizador procesa distintos elementos de diferentes maneras según su tipo. Entender estos modos te ayuda a escribir LaTeX correcto y evitar errores comunes. </p><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Modo Raw</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> En el <strong data-v-1e75afea>modo raw</strong>, el contenido se recopila como texto plano y se pasa directamente al renderizador sin procesamiento adicional. Se usa para: </p><ul class="list-disc list-inside text-gray-600 mb-4 space-y-1" data-v-1e75afea><li data-v-1e75afea>Entornos matemáticos (<code class="code-inline" data-v-1e75afea>equation</code>, <code class="code-inline" data-v-1e75afea>align</code>, <code class="code-inline" data-v-1e75afea>cases</code>, <code class="code-inline" data-v-1e75afea>pmatrix</code>)</li><li data-v-1e75afea>El entorno <code class="code-inline" data-v-1e75afea>verbatim</code></li><li data-v-1e75afea>Rutas de imágenes en <code class="code-inline" data-v-1e75afea>\\includegraphics</code></li><li data-v-1e75afea>URLs en <code class="code-inline" data-v-1e75afea>\\url</code></li></ul><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{equation}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> \\int_a^b f(x)\\,dx = F(b) - F(a)</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{equation}</span></div><div class="mt-3" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\includegraphics</span><span class="text-gray-300" data-v-1e75afea>{assets/diagram.png}</span></div></div><p class="text-gray-600 text-sm mb-8" data-v-1e75afea> Dentro de entornos raw no puedes usar otros comandos LaTeX ni formato. El contenido se pasa directamente a KaTeX (para matemáticas) o se renderiza tal cual (para verbatim). </p><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Modo Clave-Valor (kv)</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> El <strong data-v-1e75afea>modo clave-valor</strong> lo usan los entornos personalizados como <code class="code-inline" data-v-1e75afea>theorem</code>, <code class="code-inline" data-v-1e75afea>definition</code>, etc. Los parámetros se pasan en un bloque de corchetes con sintaxis <code class="code-inline" data-v-1e75afea>clave=valor</code>: </p><div class="code-block mb-4" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{theorem}[</span><span class="text-green-300" data-v-1e75afea>label</span><span class="text-gray-300" data-v-1e75afea>=</span><span class="text-yellow-300" data-v-1e75afea>main-thm</span><span class="text-gray-300" data-v-1e75afea>, </span><span class="text-green-300" data-v-1e75afea>title</span><span class="text-gray-300" data-v-1e75afea>=</span><span class="text-yellow-300" data-v-1e75afea>Pythagorean Theorem</span><span class="text-gray-300" data-v-1e75afea>]</span></div><p class="text-gray-600 text-sm mb-4 leading-relaxed" data-v-1e75afea> Claves disponibles: </p><ul class="list-disc list-inside text-gray-600 mb-4 space-y-1" data-v-1e75afea><li data-v-1e75afea><code class="code-inline" data-v-1e75afea>label</code> — identificador para referencias cruzadas</li><li data-v-1e75afea><code class="code-inline" data-v-1e75afea>title</code> — nombre mostrado en el encabezado</li><li data-v-1e75afea><code class="code-inline" data-v-1e75afea>aside</code> — texto de anotación lateral</li></ul><p class="text-gray-600 text-sm mb-8" data-v-1e75afea> Si no se proveen corchetes, se usa un diccionario de parámetros vacío. Las claves sin valor (p.ej., <code class="code-inline" data-v-1e75afea>[highlight]</code>) se tratan como banderas booleanas con valor <code class="code-inline" data-v-1e75afea>true</code>. </p><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Modo Parsed</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> En el <strong data-v-1e75afea>modo parsed</strong>, el contenido entre llaves se procesa como LaTeX normal. Puedes usar comandos de formato, matemáticas en línea y estructuras anidadas: </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\textbf</span><span class="text-gray-300" data-v-1e75afea>{This is }</span><span class="text-blue-300" data-v-1e75afea>\\textit</span><span class="text-gray-300" data-v-1e75afea>{formatted}</span><span class="text-gray-300" data-v-1e75afea> text.</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>The formula $a^2 + b^2 = c^2$ uses inline math.</span></div></div><p class="text-gray-600 text-sm mb-8" data-v-1e75afea> Los comandos de formato como <code class="code-inline" data-v-1e75afea>\\textbf</code>, <code class="code-inline" data-v-1e75afea>\\textit</code> y las matemáticas en línea funcionan dentro del contenido parsed. </p><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Elementos Solo en Línea</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Algunos elementos están restringidos a contenido <strong data-v-1e75afea>solo en línea</strong>. Esto significa: </p><ul class="list-disc list-inside text-gray-600 mb-4 space-y-1" data-v-1e75afea><li data-v-1e75afea>Las matemáticas en bloque (<code class="code-inline" data-v-1e75afea>$$...$$</code>) no están permitidas</li><li data-v-1e75afea>No se pueden anidar entornos dentro de ellos</li><li data-v-1e75afea>Las matemáticas en línea (<code class="code-inline" data-v-1e75afea>$...$</code>) sí están permitidas</li></ul><p class="text-gray-600 text-sm mb-4" data-v-1e75afea> El comando <code class="code-inline" data-v-1e75afea>\\note</code> es solo en línea por diseño: los tooltips no pueden contener bloques grandes de contenido. </p><div class="doc-block mb-8" data-v-1e75afea><p class="doc-block-title" data-v-1e75afea>¿Por qué solo en línea?</p><p class="text-gray-700 text-sm leading-relaxed" data-v-1e75afea> Elementos como las notas están diseñados para anotaciones pequeñas. Matemáticas en bloque o entornos dentro de ellos producirían tooltips poco manejables. El analizador impone esta restricción para garantizar una experiencia de lectura coherente. </p></div></section><hr class="border-gray-200 mb-14" data-v-1e75afea><section id="environments" class="mb-14" data-v-1e75afea><h2 class="text-2xl font-bold font-plex mb-2" data-v-1e75afea>Entornos</h2><p class="text-sm text-gray-400 mb-6" data-v-1e75afea>Entornos matemáticos y estructurales</p><p class="text-gray-700 mb-8 leading-relaxed" data-v-1e75afea> Los entornos envuelven contenido entre <code class="code-inline" data-v-1e75afea>\\begin{nombre}</code> y <code class="code-inline" data-v-1e75afea>\\end{nombre}</code>. Los entornos personalizados usan parámetros clave-valor; los entornos LaTeX estándar usan su sintaxis nativa. </p><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Entornos Matemáticos (Raw)</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Los entornos matemáticos recopilan su contenido como LaTeX raw y lo pasan directamente a KaTeX. No se procesan comandos anidados ni formato dentro de ellos. </p><div class="flex flex-col gap-4 mb-8" data-v-1e75afea><div class="rounded-xl border border-gray-200 bg-white p-5" data-v-1e75afea><p class="font-mono font-semibold text-gray-800 mb-2" data-v-1e75afea><code class="code-inline" data-v-1e75afea>equation</code></p><p class="text-gray-600 text-sm mb-3" data-v-1e75afea>Ecuación en bloque de una línea. El contenido es LaTeX raw para KaTeX.</p><div class="code-block" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{equation}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> E = mc^2</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{equation}</span></div></div></div><div class="rounded-xl border border-gray-200 bg-white p-5" data-v-1e75afea><p class="font-mono font-semibold text-gray-800 mb-2" data-v-1e75afea><code class="code-inline" data-v-1e75afea>align</code></p><p class="text-gray-600 text-sm mb-3" data-v-1e75afea>Ecuaciones alineadas de múltiples líneas. Usa <code class="code-inline" data-v-1e75afea>&amp;</code> para los puntos de alineación.</p><div class="code-block" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{align}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> (a+b)^2 &amp;= a^2 + 2ab + b^2 \\\\</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> (a-b)^2 &amp;= a^2 - 2ab + b^2</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{align}</span></div></div></div><div class="rounded-xl border border-gray-200 bg-white p-5" data-v-1e75afea><p class="font-mono font-semibold text-gray-800 mb-2" data-v-1e75afea><code class="code-inline" data-v-1e75afea>cases</code></p><p class="text-gray-600 text-sm mb-3" data-v-1e75afea>Definiciones de funciones por partes.</p><div class="code-block" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{cases}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> f(x) = x^2 \\quad \\text{if } x \\geq 0 \\\\</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> f(x) = 0 \\quad \\text{otherwise}</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{cases}</span></div></div></div><div class="rounded-xl border border-gray-200 bg-white p-5" data-v-1e75afea><p class="font-mono font-semibold text-gray-800 mb-2" data-v-1e75afea><code class="code-inline" data-v-1e75afea>pmatrix</code></p><p class="text-gray-600 text-sm mb-3" data-v-1e75afea>Matriz entre paréntesis.</p><div class="code-block" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{pmatrix}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> 1 &amp; 0 &amp; 0 \\\\</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> 0 &amp; 1 &amp; 0 \\\\</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> 0 &amp; 0 &amp; 1</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{pmatrix}</span></div></div></div></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Abreviaciones para Matemáticas en Bloque</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> También puedes usar sintaxis abreviada para matemáticas en bloque. Las tres formas son equivalentes: </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea>$$ \\int_a^b f(x)\\,dx $$</span></div><div class="mt-3" data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea>\\[ \\sum_{n=1}^{\\infty} \\frac{1}{n^2} \\]</span></div><div class="mt-3" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{equation}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> \\lim_{x \\to \\infty} f(x)</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{equation}</span></div></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Entornos Matemáticos (Clave-Valor)</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Estos entornos aceptan parámetros clave-valor opcionales. Todos comparten el mismo sistema de parámetros con las claves <code class="code-inline" data-v-1e75afea>label</code>, <code class="code-inline" data-v-1e75afea>title</code> y <code class="code-inline" data-v-1e75afea>aside</code>. </p><div class="overflow-x-auto mb-6" data-v-1e75afea><table class="w-full text-sm text-left border-collapse" data-v-1e75afea><thead data-v-1e75afea><tr class="border-b border-gray-200" data-v-1e75afea><th class="py-2 pr-6 font-semibold text-gray-700" data-v-1e75afea>Entorno</th><th class="py-2 font-semibold text-gray-700" data-v-1e75afea>Descripción</th></tr></thead><tbody class="text-gray-600" data-v-1e75afea><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>theorem</code></td><td class="py-2" data-v-1e75afea>Enunciado formal de un teorema</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>definition</code></td><td class="py-2" data-v-1e75afea>Definición formal</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>axiom</code></td><td class="py-2" data-v-1e75afea>Axioma o postulado</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>lemma</code></td><td class="py-2" data-v-1e75afea>Lema auxiliar</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>proposition</code></td><td class="py-2" data-v-1e75afea>Proposición matemática</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>corollary</code></td><td class="py-2" data-v-1e75afea>Corolario derivado de un teorema</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>proof</code></td><td class="py-2" data-v-1e75afea>Demostración de un enunciado</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>exercise</code></td><td class="py-2" data-v-1e75afea>Ejercicio o problema de práctica</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>convention</code></td><td class="py-2" data-v-1e75afea>Convención o acuerdo de notación</td></tr><tr data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>block</code></td><td class="py-2" data-v-1e75afea>Contenedor con pestañas (cada <code class="code-inline" data-v-1e75afea>\\item</code> se convierte en una pestaña)</td></tr></tbody></table></div><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Ejemplo con parámetros completos: </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{theorem}[</span><span class="text-green-300" data-v-1e75afea>label</span><span class="text-gray-300" data-v-1e75afea>=</span><span class="text-yellow-300" data-v-1e75afea>pythagorean</span><span class="text-gray-300" data-v-1e75afea>, </span><span class="text-green-300" data-v-1e75afea>title</span><span class="text-gray-300" data-v-1e75afea>=</span><span class="text-yellow-300" data-v-1e75afea>Pythagorean Theorem</span><span class="text-gray-300" data-v-1e75afea>]</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea> In a right triangle, $a^2 + b^2 = c^2$ where $c$ is the hypotenuse.</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{theorem}</span></div><div class="mt-3" data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>See </span><span class="text-blue-300" data-v-1e75afea>\\ref</span><span class="text-gray-300" data-v-1e75afea>{pythagorean} for details.</span></div></div><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Sin parámetros (usa el estilo por defecto): </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{lemma}</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea> If $f$ is continuous on $[a,b]$, then $f$ is bounded.</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{lemma}</span></div></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Entornos de Lista</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Usa <code class="code-inline" data-v-1e75afea>enumerate</code> para listas numeradas e <code class="code-inline" data-v-1e75afea>itemize</code> para listas con viñetas. Cada elemento comienza con <code class="code-inline" data-v-1e75afea>\\item</code>. Un nuevo <code class="code-inline" data-v-1e75afea>\\item</code> cierra automáticamente el anterior. </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{enumerate}</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea> \\item</span><span class="text-gray-300" data-v-1e75afea> First step</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea> \\item</span><span class="text-gray-300" data-v-1e75afea> Second step</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea> \\item</span><span class="text-gray-300" data-v-1e75afea> Third step</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{enumerate}</span></div><div class="mt-3" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{itemize}</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea> \\item</span><span class="text-gray-300" data-v-1e75afea> Apple</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea> \\item</span><span class="text-gray-300" data-v-1e75afea> Banana</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea> \\item</span><span class="text-gray-300" data-v-1e75afea> Cherry</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{itemize}</span></div></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Entorno Figure</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Envuelve imágenes con <code class="code-inline" data-v-1e75afea>\\includegraphics</code> y <code class="code-inline" data-v-1e75afea>\\caption</code> dentro de un entorno <code class="code-inline" data-v-1e75afea>figure</code>. El entorno acepta un parámetro opcional <code class="code-inline" data-v-1e75afea>[width=N]</code>. </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{figure}[</span><span class="text-green-300" data-v-1e75afea>width</span><span class="text-gray-300" data-v-1e75afea>=</span><span class="text-yellow-300" data-v-1e75afea>60</span><span class="text-gray-300" data-v-1e75afea>]</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea> \\includegraphics</span><span class="text-gray-300" data-v-1e75afea>{assets/diagram.png}</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea> \\caption</span><span class="text-gray-300" data-v-1e75afea>{Architecture diagram}</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{figure}</span></div></div><p class="text-gray-600 text-sm mb-8" data-v-1e75afea> Las rutas de imagen son relativas a la carpeta de assets del libro. El ancho es un valor porcentual (p.ej., <code class="code-inline" data-v-1e75afea>60</code> significa el 60% del ancho del contenedor). </p><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Entorno Verbatim</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Usa <code class="code-inline" data-v-1e75afea>verbatim</code> para texto preformateado donde los comandos LaTeX no deben procesarse: </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{verbatim}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> \\documentclass{article}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> \\begin{document}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> Hello World</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> \\end{document}</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{verbatim}</span></div></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Entorno Tabular</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Crea tablas con el entorno <code class="code-inline" data-v-1e75afea>tabular</code>. La alineación de columnas se especifica entre llaves: <code class="code-inline" data-v-1e75afea>l</code> (izquierda), <code class="code-inline" data-v-1e75afea>c</code> (centro), <code class="code-inline" data-v-1e75afea>r</code> (derecha). Usa <code class="code-inline" data-v-1e75afea>|</code> para bordes verticales y <code class="code-inline" data-v-1e75afea>\\hline</code> para líneas horizontales. </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{tabular}{</span><span class="text-yellow-300" data-v-1e75afea>|l|c|r|</span><span class="text-gray-300" data-v-1e75afea>}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> \\hline</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> Name &amp; Age &amp; City \\\\</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> \\hline</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> Alice &amp; 25 &amp; NYC \\\\</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> Bob &amp; 30 &amp; LA \\\\</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> \\hline</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{tabular}</span></div></div><p class="text-gray-600 text-sm mb-8" data-v-1e75afea> Las celdas pueden contener matemáticas en línea: <code class="code-inline" data-v-1e75afea>$x^2$</code>. Sin embargo, no se admiten entornos ni formato complejo dentro de las celdas. </p></section><hr class="border-gray-200 mb-14" data-v-1e75afea><section id="math" class="mb-14" data-v-1e75afea><h2 class="text-2xl font-bold font-plex mb-2" data-v-1e75afea>Expresiones Matemáticas</h2><p class="text-sm text-gray-400 mb-6" data-v-1e75afea>Matemáticas en línea y en bloque con KaTeX</p><p class="text-gray-700 mb-6 leading-relaxed" data-v-1e75afea> El contenido matemático se renderiza con <code class="code-inline" data-v-1e75afea>KaTeX</code>. Se admiten completamente los modos en línea y en bloque. El contenido matemático se pasa directamente a KaTeX sin procesamiento adicional. </p><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Matemáticas en Línea</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Envuelve las expresiones entre signos de dólar simples: <code class="code-inline" data-v-1e75afea>$...$</code></p><div class="code-block mb-6" data-v-1e75afea><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>The formula </span><span class="text-yellow-300" data-v-1e75afea>$e^{i\\pi} + 1 = 0$</span><span class="text-gray-300" data-v-1e75afea> is Euler&#39;s identity.</span></div><div class="mt-3" data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>If $x \\in \\mathbb{R}$ and $x &gt; 0$, then $\\sqrt{x}$ exists.</span></div></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Matemáticas en Bloque</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Para ecuaciones centradas y destacadas, usa matemáticas en bloque. Se admiten tres formas equivalentes: </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea>$$\\int_a^b f(x)\\,dx = F(b) - F(a)$$</span></div><div class="mt-3" data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea>\\[ \\sum_{n=1}^{\\infty} \\frac{1}{n^2} = \\frac{\\pi^2}{6} \\]</span></div><div class="mt-3" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{equation}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> \\lim_{x \\to 0} \\frac{\\sin x}{x} = 1</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{equation}</span></div></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Comandos Matemáticos Comunes</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> KaTeX soporta la mayoría de los comandos matemáticos LaTeX estándar. Aquí algunos comunes: </p><div class="overflow-x-auto mb-6" data-v-1e75afea><table class="w-full text-sm text-left border-collapse" data-v-1e75afea><thead data-v-1e75afea><tr class="border-b border-gray-200" data-v-1e75afea><th class="py-2 pr-6 font-semibold text-gray-700" data-v-1e75afea>Expresión</th><th class="py-2 pr-6 font-semibold text-gray-700" data-v-1e75afea>LaTeX</th><th class="py-2 font-semibold text-gray-700" data-v-1e75afea>Descripción</th></tr></thead><tbody class="text-gray-600" data-v-1e75afea><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>x<sup data-v-1e75afea>2</sup></span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>x^2</code></td><td class="py-2" data-v-1e75afea>Superíndice</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>x<sub data-v-1e75afea>i</sub></span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>x_i</code></td><td class="py-2" data-v-1e75afea>Subíndice</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>½</span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\frac{1}{2}</code></td><td class="py-2" data-v-1e75afea>Fracción</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>√x</span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\sqrt{x}</code></td><td class="py-2" data-v-1e75afea>Raíz cuadrada</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>∑</span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\sum</code></td><td class="py-2" data-v-1e75afea>Sumatoria</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>∫</span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\int</code></td><td class="py-2" data-v-1e75afea>Integral</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>∈</span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\in</code></td><td class="py-2" data-v-1e75afea>Elemento de</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>∀</span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\forall</code></td><td class="py-2" data-v-1e75afea>Para todo</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>∃</span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\exists</code></td><td class="py-2" data-v-1e75afea>Existe</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>ℜ</span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\mathbb{R}</code></td><td class="py-2" data-v-1e75afea>Negrita de pizarrón (conjuntos)</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>→</span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\rightarrow</code></td><td class="py-2" data-v-1e75afea>Flecha de implicación</td></tr><tr data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><span class="math-expr" data-v-1e75afea>↔</span></td><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\leftrightarrow</code></td><td class="py-2" data-v-1e75afea>Flecha de equivalencia</td></tr></tbody></table></div><div class="doc-block" data-v-1e75afea><p class="doc-block-title" data-v-1e75afea>Nota sobre el análisis matemático</p><p class="text-gray-700 text-sm leading-relaxed" data-v-1e75afea> Dentro de los entornos matemáticos, el contenido se pasa directamente a KaTeX. No puedes usar comandos de formato como <code class="code-inline" data-v-1e75afea>\\textbf</code> dentro de matemáticas. Usa <code class="code-inline" data-v-1e75afea>\\text{...}</code> para texto normal dentro del modo matemático. </p></div></section><hr class="border-gray-200 mb-14" data-v-1e75afea><section id="commands" class="mb-14" data-v-1e75afea><h2 class="text-2xl font-bold font-plex mb-2" data-v-1e75afea>Comandos de Texto</h2><p class="text-sm text-gray-400 mb-6" data-v-1e75afea>Formato, estructura y elementos especiales</p><p class="text-gray-700 mb-8 leading-relaxed" data-v-1e75afea> Los comandos siguen la sintaxis estándar de LaTeX: una barra invertida seguida del nombre del comando y sus argumentos entre llaves. Los argumentos opcionales usan corchetes. </p><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Encabezados</h3><div class="overflow-x-auto mb-6" data-v-1e75afea><table class="w-full text-sm text-left border-collapse" data-v-1e75afea><thead data-v-1e75afea><tr class="border-b border-gray-200" data-v-1e75afea><th class="py-2 pr-6 font-semibold text-gray-700" data-v-1e75afea>Comando</th><th class="py-2 font-semibold text-gray-700" data-v-1e75afea>Descripción</th></tr></thead><tbody class="text-gray-600" data-v-1e75afea><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\chapter{title}</code></td><td class="py-2" data-v-1e75afea>Encabezado nivel 0 (capítulo)</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\section{title}</code></td><td class="py-2" data-v-1e75afea>Encabezado nivel 1</td></tr><tr data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\subsection{title}</code></td><td class="py-2" data-v-1e75afea>Encabezado nivel 2</td></tr></tbody></table></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Formato de Texto</h3><div class="overflow-x-auto mb-6" data-v-1e75afea><table class="w-full text-sm text-left border-collapse" data-v-1e75afea><thead data-v-1e75afea><tr class="border-b border-gray-200" data-v-1e75afea><th class="py-2 pr-6 font-semibold text-gray-700" data-v-1e75afea>Comando</th><th class="py-2 font-semibold text-gray-700" data-v-1e75afea>Descripción</th></tr></thead><tbody class="text-gray-600" data-v-1e75afea><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\textbf{text}</code></td><td class="py-2" data-v-1e75afea>Texto en negrita</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\textit{text}</code></td><td class="py-2" data-v-1e75afea>Texto en cursiva</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\emph{text}</code></td><td class="py-2" data-v-1e75afea>Énfasis (normalmente cursiva)</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\underline{text}</code></td><td class="py-2" data-v-1e75afea>Texto subrayado</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\texttt{text}</code></td><td class="py-2" data-v-1e75afea>Texto monoespaciado (máquina de escribir)</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\textsf{text}</code></td><td class="py-2" data-v-1e75afea>Texto sin serifa</td></tr><tr data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\psc{text}</code></td><td class="py-2" data-v-1e75afea>Texto en versalitas</td></tr></tbody></table></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Elementos Especiales</h3><div class="overflow-x-auto mb-6" data-v-1e75afea><table class="w-full text-sm text-left border-collapse" data-v-1e75afea><thead data-v-1e75afea><tr class="border-b border-gray-200" data-v-1e75afea><th class="py-2 pr-6 font-semibold text-gray-700" data-v-1e75afea>Comando</th><th class="py-2 font-semibold text-gray-700" data-v-1e75afea>Descripción</th></tr></thead><tbody class="text-gray-600" data-v-1e75afea><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\url{path}</code></td><td class="py-2" data-v-1e75afea>URL de hipervínculo (raw, no analizado)</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\note[key=val]{text}</code></td><td class="py-2" data-v-1e75afea>Nota tooltip en línea. Acepta las claves <code class="code-inline" data-v-1e75afea>title</code> y <code class="code-inline" data-v-1e75afea>aside</code>.</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\alert{text}</code></td><td class="py-2" data-v-1e75afea>Caja de alerta o advertencia destacada</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\includegraphics[width=N]{path}</code></td><td class="py-2" data-v-1e75afea>Imagen con porcentaje de ancho opcional</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\caption{text}</code></td><td class="py-2" data-v-1e75afea>Leyenda de figura (dentro del entorno figure)</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\label{id}</code></td><td class="py-2" data-v-1e75afea>Define una etiqueta para referencias cruzadas</td></tr><tr data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\ref{label}</code></td><td class="py-2" data-v-1e75afea>Referencia cruzada a un elemento etiquetado</td></tr></tbody></table></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Comandos Autocerrados</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Estos comandos no toman argumentos y se escriben sin llaves: </p><div class="overflow-x-auto mb-6" data-v-1e75afea><table class="w-full text-sm text-left border-collapse" data-v-1e75afea><thead data-v-1e75afea><tr class="border-b border-gray-200" data-v-1e75afea><th class="py-2 pr-6 font-semibold text-gray-700" data-v-1e75afea>Comando</th><th class="py-2 font-semibold text-gray-700" data-v-1e75afea>Descripción</th></tr></thead><tbody class="text-gray-600" data-v-1e75afea><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\newline</code> o <code class="code-inline" data-v-1e75afea>\\n</code></td><td class="py-2" data-v-1e75afea>Salto de línea</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\\\</code></td><td class="py-2" data-v-1e75afea>Salto de línea alternativo</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\newpage</code></td><td class="py-2" data-v-1e75afea>Salto de página</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\noindent</code></td><td class="py-2" data-v-1e75afea>Suprime la sangría del párrafo</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\qed</code></td><td class="py-2" data-v-1e75afea>Símbolo de fin de demostración (cuadrado)</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\obs</code></td><td class="py-2" data-v-1e75afea>Marcador de observación</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\dem</code></td><td class="py-2" data-v-1e75afea>Marcador de demostración</td></tr><tr data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\backslash</code></td><td class="py-2" data-v-1e75afea>Carácter de barra invertida literal</td></tr></tbody></table></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Caracteres Escapados</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Estos caracteres tienen significado especial en LaTeX. Usa una barra invertida para producirlos literalmente: </p><div class="overflow-x-auto mb-8" data-v-1e75afea><table class="w-full text-sm text-left border-collapse" data-v-1e75afea><thead data-v-1e75afea><tr class="border-b border-gray-200" data-v-1e75afea><th class="py-2 pr-6 font-semibold text-gray-700" data-v-1e75afea>Carácter</th><th class="py-2 pr-6 font-semibold text-gray-700" data-v-1e75afea>Escapado</th></tr></thead><tbody class="text-gray-600" data-v-1e75afea><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>{ }</code></td><td class="py-2" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\{ \\}</code></td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>$</code></td><td class="py-2" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\$</code></td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>%</code></td><td class="py-2" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\%</code></td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>&amp;</code></td><td class="py-2" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\&amp;</code></td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>#</code></td><td class="py-2" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\#</code></td></tr><tr data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>_</code></td><td class="py-2" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\_</code></td></tr></tbody></table></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Comentarios</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Las líneas que empiezan con <code class="code-inline" data-v-1e75afea>%</code> se tratan como comentarios y se eliminan antes del análisis: </p><div class="code-block mb-8" data-v-1e75afea><div data-v-1e75afea><span class="text-gray-500" data-v-1e75afea>% This entire line is ignored</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>This text appears.</span></div><div data-v-1e75afea><span class="text-gray-500" data-v-1e75afea>% So is this line.</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>But this appears.</span></div></div></section><hr class="border-gray-200 mb-14" data-v-1e75afea><section id="cross-references" class="mb-14" data-v-1e75afea><h2 class="text-2xl font-bold font-plex mb-2" data-v-1e75afea>Referencias Cruzadas</h2><p class="text-sm text-gray-400 mb-6" data-v-1e75afea>Etiqueta y referencia elementos dentro de tu documento</p><p class="text-gray-700 mb-6 leading-relaxed" data-v-1e75afea> Puedes crear referencias cruzadas clicables a teoremas, definiciones, ecuaciones y otros elementos etiquetados. Esto requiere dos pasos: etiquetar y referenciar. </p><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Crear Etiquetas</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Agrega una clave <code class="code-inline" data-v-1e75afea>label</code> a cualquier entorno que soporte parámetros clave-valor: </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{theorem}[</span><span class="text-green-300" data-v-1e75afea>label</span><span class="text-gray-300" data-v-1e75afea>=</span><span class="text-yellow-300" data-v-1e75afea>main-theorem</span><span class="text-gray-300" data-v-1e75afea>, </span><span class="text-green-300" data-v-1e75afea>title</span><span class="text-gray-300" data-v-1e75afea>=</span><span class="text-yellow-300" data-v-1e75afea>Main Result</span><span class="text-gray-300" data-v-1e75afea>]</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea> The statement of your theorem...</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{theorem}</span></div></div><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> O usa el comando <code class="code-inline" data-v-1e75afea>\\label</code> después de una ecuación: </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{equation}</span></div><div data-v-1e75afea><span class="text-yellow-300" data-v-1e75afea> E = mc^2</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{equation}</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\label</span><span class="text-gray-300" data-v-1e75afea>{eq-einstein}</span></div></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Referenciar Etiquetas</h3><p class="text-gray-700 mb-4 leading-relaxed" data-v-1e75afea> Usa <code class="code-inline" data-v-1e75afea>\\ref{label}</code> para crear una referencia: </p><div class="code-block mb-4" data-v-1e75afea><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>As shown in </span><span class="text-blue-300" data-v-1e75afea>\\ref</span><span class="text-gray-300" data-v-1e75afea>{main-theorem}, we have...</span></div><div class="mt-2" data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>From equation </span><span class="text-blue-300" data-v-1e75afea>\\ref</span><span class="text-gray-300" data-v-1e75afea>{eq-einstein}...</span></div></div><div class="doc-block" data-v-1e75afea><p class="doc-block-title" data-v-1e75afea>Las etiquetas deben ser únicas</p><p class="text-gray-700 text-sm leading-relaxed" data-v-1e75afea> Cada etiqueta debe ser única dentro del documento. Usar la misma etiqueta dos veces producirá un error durante el análisis. </p></div></section><hr class="border-gray-200 mb-14" data-v-1e75afea><section id="complete-example" class="mb-14" data-v-1e75afea><h2 class="text-2xl font-bold font-plex mb-2" data-v-1e75afea>Ejemplo Completo</h2><p class="text-sm text-gray-400 mb-6" data-v-1e75afea>Un documento completo que demuestra los patrones más comunes</p><div class="code-block" style="max-height:500px;overflow-y:auto;" data-v-1e75afea><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\documentclass</span><span class="text-gray-300" data-v-1e75afea>{article}</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{document}</span></div><div class="mt-2" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\section</span><span class="text-gray-300" data-v-1e75afea>{Introduction to Real Analysis}</span></div><div class="mt-2" data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>In this section we introduce the concept of </span><span class="text-blue-300" data-v-1e75afea>\\textit</span><span class="text-gray-300" data-v-1e75afea>{continuity}</span><span class="text-gray-300" data-v-1e75afea>.</span></div><div class="mt-2" data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>A function $f: \\mathbb{R} \\to \\mathbb{R}$ is continuous at $a$ if:</span></div><div class="mt-3" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{definition}[</span><span class="text-green-300" data-v-1e75afea>label</span><span class="text-gray-300" data-v-1e75afea>=</span><span class="text-yellow-300" data-v-1e75afea>def-continuity</span><span class="text-gray-300" data-v-1e75afea>, </span><span class="text-green-300" data-v-1e75afea>title</span><span class="text-gray-300" data-v-1e75afea>=</span><span class="text-yellow-300" data-v-1e75afea>Continuity</span><span class="text-gray-300" data-v-1e75afea>]</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea> $\\forall \\epsilon &gt; 0, \\exists \\delta &gt; 0$ such that</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea> $|x - a| &lt; \\delta \\implies |f(x) - f(a)| &lt; \\epsilon$.</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{definition}</span></div><div class="mt-3" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{theorem}[</span><span class="text-green-300" data-v-1e75afea>label</span><span class="text-gray-300" data-v-1e75afea>=</span><span class="text-yellow-300" data-v-1e75afea>thm-intermediate</span><span class="text-gray-300" data-v-1e75afea>]</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea> If $f$ is continuous on $[a,b]$ and $f(a) \\neq f(b)$,</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea> then $f$ takes every value between $f(a)$ and $f(b)$.</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{theorem}</span></div><div class="mt-3" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{proof}</span></div><div data-v-1e75afea><span class="text-gray-300" data-v-1e75afea> Consider the set $S = \\{x \\in [a,b] : f(x) \\leq c\\}$...</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\qed</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{proof}</span></div><div class="mt-3" data-v-1e75afea><span class="text-gray-300" data-v-1e75afea>See </span><span class="text-blue-300" data-v-1e75afea>\\ref</span><span class="text-gray-300" data-v-1e75afea>{def-continuity} and </span><span class="text-blue-300" data-v-1e75afea>\\ref</span><span class="text-gray-300" data-v-1e75afea>{thm-intermediate} for details.</span></div><div class="mt-3" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\begin</span><span class="text-gray-300" data-v-1e75afea>{enumerate}</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea> \\item</span><span class="text-gray-300" data-v-1e75afea> Define continuity carefully</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea> \\item</span><span class="text-gray-300" data-v-1e75afea> State the Intermediate Value Theorem</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea> \\item</span><span class="text-gray-300" data-v-1e75afea> Provide a proof</span></div><div data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{enumerate}</span></div><div class="mt-3" data-v-1e75afea><span class="text-blue-300" data-v-1e75afea>\\end</span><span class="text-gray-300" data-v-1e75afea>{document}</span></div></div></section><hr class="border-gray-200 mb-14" data-v-1e75afea><section id="parser-output" class="mb-14" data-v-1e75afea><h2 class="text-2xl font-bold font-plex mb-2" data-v-1e75afea>Salida del Analizador</h2><p class="text-sm text-gray-400 mb-6" data-v-1e75afea>Estructura JSON del AST y tipos de nodos</p><p class="text-gray-700 mb-6 leading-relaxed" data-v-1e75afea> El analizador genera un objeto JSON con tres claves principales: </p><div class="overflow-x-auto mb-8" data-v-1e75afea><table class="w-full text-sm text-left border-collapse" data-v-1e75afea><thead data-v-1e75afea><tr class="border-b border-gray-200" data-v-1e75afea><th class="py-2 pr-6 font-semibold text-gray-700" data-v-1e75afea>Clave</th><th class="py-2 font-semibold text-gray-700" data-v-1e75afea>Descripción</th></tr></thead><tbody class="text-gray-600" data-v-1e75afea><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>content</code></td><td class="py-2" data-v-1e75afea>Array de nodos AST (encabezados, párrafos, entornos, etc.)</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>refs</code></td><td class="py-2" data-v-1e75afea>Diccionario que mapea IDs de etiquetas a sus índices</td></tr><tr data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>chapters</code></td><td class="py-2" data-v-1e75afea>Diccionario de metadatos de capítulos (índice, título)</td></tr></tbody></table></div><h3 class="text-lg font-semibold font-plex mb-3" data-v-1e75afea>Tipos de Nodo (campo kind)</h3><div class="overflow-x-auto mb-8" data-v-1e75afea><table class="w-full text-sm text-left border-collapse" data-v-1e75afea><thead data-v-1e75afea><tr class="border-b border-gray-200" data-v-1e75afea><th class="py-2 pr-6 font-semibold text-gray-700" data-v-1e75afea>Kind</th><th class="py-2 font-semibold text-gray-700" data-v-1e75afea>Descripción</th></tr></thead><tbody class="text-gray-600" data-v-1e75afea><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>heading</code></td><td class="py-2" data-v-1e75afea>Capítulo/Sección. Tiene <code class="code-inline" data-v-1e75afea>level</code> (0=capítulo, 1=sección, 2=subsección)</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>bold</code>, <code class="code-inline" data-v-1e75afea>italic</code>, etc.</td><td class="py-2" data-v-1e75afea>Nodos de formato de texto. Contienen un array <code class="code-inline" data-v-1e75afea>content</code></td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>math</code></td><td class="py-2" data-v-1e75afea>Expresión matemática. Tiene <code class="code-inline" data-v-1e75afea>mode</code> (inline/display) y <code class="code-inline" data-v-1e75afea>raw</code> (LaTeX para KaTeX)</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>list</code></td><td class="py-2" data-v-1e75afea>Lista ordenada/no ordenada. Tiene booleano <code class="code-inline" data-v-1e75afea>ordered</code> y array <code class="code-inline" data-v-1e75afea>content</code></td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>item</code></td><td class="py-2" data-v-1e75afea>Elemento de lista. Contiene array <code class="code-inline" data-v-1e75afea>content</code></td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>theorem</code>, <code class="code-inline" data-v-1e75afea>definition</code>, etc.</td><td class="py-2" data-v-1e75afea>Entornos matemáticos. Contienen array <code class="code-inline" data-v-1e75afea>content</code> y <code class="code-inline" data-v-1e75afea>params</code> opcional</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>note</code></td><td class="py-2" data-v-1e75afea>Nota tooltip. Tiene <code class="code-inline" data-v-1e75afea>params</code> y <code class="code-inline" data-v-1e75afea>content</code>. Solo en línea.</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>figure</code></td><td class="py-2" data-v-1e75afea>Contenedor de imagen. Contiene nodos <code class="code-inline" data-v-1e75afea>image</code> y <code class="code-inline" data-v-1e75afea>caption</code></td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>image</code></td><td class="py-2" data-v-1e75afea>Nodo de imagen. Tiene <code class="code-inline" data-v-1e75afea>params</code> con <code class="code-inline" data-v-1e75afea>width</code></td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>table</code></td><td class="py-2" data-v-1e75afea>Tabla. Tiene arrays <code class="code-inline" data-v-1e75afea>columns</code> y <code class="code-inline" data-v-1e75afea>rows</code></td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>verbatim</code></td><td class="py-2" data-v-1e75afea>Texto preformateado. Tiene <code class="code-inline" data-v-1e75afea>content</code> con cadena de texto raw</td></tr><tr class="border-b border-gray-100" data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>label</code></td><td class="py-2" data-v-1e75afea>Definición de etiqueta. Tiene <code class="code-inline" data-v-1e75afea>id</code> e <code class="code-inline" data-v-1e75afea>index</code></td></tr><tr data-v-1e75afea><td class="py-2 pr-6" data-v-1e75afea><code class="code-inline" data-v-1e75afea>ref</code></td><td class="py-2" data-v-1e75afea>Referencia cruzada. Tiene <code class="code-inline" data-v-1e75afea>target</code> e <code class="code-inline" data-v-1e75afea>index</code></td></tr></tbody></table></div></section><hr class="border-gray-200 mb-14" data-v-1e75afea><section id="limitations" class="mb-14" data-v-1e75afea><h2 class="text-2xl font-bold font-plex mb-2" data-v-1e75afea>Limitaciones del Analizador</h2><p class="text-sm text-gray-400 mb-6" data-v-1e75afea>Lo que el analizador actualmente no soporta</p><p class="text-gray-700 mb-8 leading-relaxed" data-v-1e75afea> El analizador cubre un subconjunto seleccionado de LaTeX optimizado para contenido matemático. Las siguientes son limitaciones conocidas: </p><div class="flex flex-col gap-4" data-v-1e75afea><div class="doc-block" data-v-1e75afea><p class="doc-block-title" data-v-1e75afea>Sin definición de macros</p><p class="text-gray-700 text-sm leading-relaxed" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\newcommand</code> y <code class="code-inline" data-v-1e75afea>\\renewcommand</code> no son soportados. Define las macros en tu clase de documento o archivo de estilo. </p></div><div class="doc-block" data-v-1e75afea><p class="doc-block-title" data-v-1e75afea>Sin anidamiento profundo de encabezados</p><p class="text-gray-700 text-sm leading-relaxed" data-v-1e75afea> Solo se reconocen tres niveles: <code class="code-inline" data-v-1e75afea>\\chapter</code>, <code class="code-inline" data-v-1e75afea>\\section</code> y <code class="code-inline" data-v-1e75afea>\\subsection</code>. <code class="code-inline" data-v-1e75afea>\\subsubsection</code> y más profundos no están soportados. </p></div><div class="doc-block" data-v-1e75afea><p class="doc-block-title" data-v-1e75afea>Sin notas al pie</p><p class="text-gray-700 text-sm leading-relaxed" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\footnote</code> no está soportado. Usa <code class="code-inline" data-v-1e75afea>\\note</code> para anotaciones en línea. </p></div><div class="doc-block" data-v-1e75afea><p class="doc-block-title" data-v-1e75afea>Sin hipervínculos más allá de \\url</p><p class="text-gray-700 text-sm leading-relaxed" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\href</code> y <code class="code-inline" data-v-1e75afea>\\hyperref</code> no están soportados. <code class="code-inline" data-v-1e75afea>\\url{path}</code> produce un nodo <code class="code-inline" data-v-1e75afea>url</code>; renderizarlo como enlace clicable depende del frontend. </p></div><div class="doc-block" data-v-1e75afea><p class="doc-block-title" data-v-1e75afea>Sin TikZ ni gráficos externos</p><p class="text-gray-700 text-sm leading-relaxed" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\tikz</code> y paquetes de dibujo similares no están soportados. Usa imágenes prerenderizadas para los diagramas. </p></div><div class="doc-block" data-v-1e75afea><p class="doc-block-title" data-v-1e75afea>Sin soporte para \\input</p><p class="text-gray-700 text-sm leading-relaxed" data-v-1e75afea><code class="code-inline" data-v-1e75afea>\\input</code> no está soportado. Usa <code class="code-inline" data-v-1e75afea>\\include{path}</code> en su lugar. </p></div><div class="doc-block" data-v-1e75afea><p class="doc-block-title" data-v-1e75afea>Los comandos desconocidos se omiten silenciosamente</p><p class="text-gray-700 text-sm leading-relaxed" data-v-1e75afea> Cualquier comando que no esté en el registro se consume junto con sus argumentos pero no produce salida. No hay advertencia durante el análisis. </p></div></div></section>`,18))])]))}},M=x(z,[["__scopeId","data-v-1e75afea"]]);export{M as default};
